fix6_feed_status_wording.current:
if (!latestStreamTs) {
  txt.textContent = 'Market feed reconnecting';
} else if (payload?.stale) {
  txt.textContent = `Market feed stale · ${humanAge(latestStreamTs)}`;
} else {
  txt.textContent = 'Market feed live';
}

fix6_feed_status_wording.change_to:
